//! Byte-exact DOT serializer for [`Graph`].
//!
//! Reproduces the exact bytes the tamarin web UI emits at
//! `interactive-graph-def` (see workspace/BEHAVIOR.md §2, §3). The emission is
//! driven by one structural rule: every block is
//! `OPEN "\n"` + (each inner line + `"\n"`) + `"\n}"`, i.e. one blank line before
//! the closing brace; the top-level digraph then gets a final `"\n"`.

use crate::model::*;

/// Serialize a graph to DOT text (byte-exact against captured payloads).
pub fn to_dot(g: &Graph) -> String {
    let mut lines: Vec<String> = header_lines(g.header);
    for s in &g.body {
        lines.push(render_stmt(s));
    }
    // Top-level digraph block, plus the trailing newline the server emits.
    let mut out = render_block("digraph \"G\" {", &lines);
    out.push('\n');
    out
}

/// `OPEN\n` + `line\n`* + `\n}`  (no trailing newline; callers add it if needed).
/// A `line` may itself be multi-line (a nested block); the per-line `\n` after it
/// supplies the separator the parent owes it.
fn render_block(open: &str, lines: &[String]) -> String {
    let mut s = String::new();
    s.push_str(open);
    s.push('\n');
    for l in lines {
        s.push_str(l);
        s.push('\n');
    }
    s.push_str("\n}");
    s
}

fn header_lines(h: Header) -> Vec<String> {
    let raw: &[&str] = match h {
        Header::Simple => &[
            "nodesep=\"0.3\";",
            "ranksep=\"0.3\";",
            "node[fontsize=\"8\",fontname=\"Helvetica\",width=\"0.3\",height=\"0.2\"];",
            "edge[fontsize=\"8\",fontname=\"Helvetica\"];",
        ],
        Header::Compact => &[
            "nodesep=\"0.8\";",
            "ranksep=\"0.8\";",
            "sep=\"4\";",
            "splines=\"true\";",
            "overlap=\"false\";",
            "pack=\"true\";",
            "packmode=\"cluster\";",
            "concentrate=\"true\";",
            "compound=\"true\";",
            "remincross=\"true\";",
            "mclimit=\"10\";",
            "nslimit=\"20\";",
            "nslimit1=\"20\";",
            "ordering=\"out\";",
            "rankdir=\"TB\";",
            "showboxes=\"false\";",
            "clusterrank=\"local\";",
            "node[fontsize=\"8\",fontname=\"Helvetica\",width=\"0.3\",height=\"0.2\",margin=\"0.05,0.05\",shape=\"ellipse\"];",
            "edge[fontsize=\"8\",fontname=\"Helvetica\",penwidth=\"1.5\",arrowsize=\"0.5\",color=\"black\",style=\"solid\",weight=\"8\"];",
        ],
    };
    raw.iter().map(|s| s.to_string()).collect()
}

fn render_stmt(s: &Stmt) -> String {
    match s {
        Stmt::Node(n) => render_node(n),
        Stmt::Edge(e) => render_edge(e),
        Stmt::Cluster(c) => render_cluster(c),
        Stmt::RankBlock(b) => render_rankblock(b),
    }
}

fn render_node(n: &Node) -> String {
    match &n.kind {
        NodeKind::Record(r) => {
            format!(
                "{}[shape=\"record\",label=\"{}\",fillcolor=\"{}\",style=\"filled\",fontcolor=\"{}\",role=\"{}\"];",
                n.id,
                render_record_label(r),
                r.fillcolor,
                r.fontcolor,
                r.role.0,
            )
        }
        NodeKind::Ellipse(e) => match &e.color {
            Some(c) => format!(
                "{}[label=\"{}\",shape=\"ellipse\",color=\"{}\"];",
                n.id, e.label, c
            ),
            None => format!("{}[label=\"{}\",shape=\"ellipse\"];", n.id, e.label),
        },
        NodeKind::Plain { html } => {
            format!("{}[shape=\"plain\",label=<{}>];", n.id, html)
        }
    }
}

/// `{{<p> t|<p> t}|{<p> t}|{<p> t|<p> t}}` — outer braces, groups joined by `|`,
/// each group `{cell|cell}`, each cell `<port> text`.
fn render_record_label(r: &Record) -> String {
    let mut s = String::from("{");
    let groups: Vec<String> = r
        .columns
        .iter()
        .map(|col| {
            let cells: Vec<String> = col
                .iter()
                .map(|c| format!("<{}> {}", c.port, c.text))
                .collect();
            format!("{{{}}}", cells.join("|"))
        })
        .collect();
    s.push_str(&groups.join("|"));
    s.push('}');
    s
}

fn render_edge(e: &Edge) -> String {
    let mut s = render_endpoint(&e.src);
    s.push_str(" -> ");
    s.push_str(&render_endpoint(&e.dst));
    if !e.attrs.is_empty() {
        let attrs: Vec<String> = e
            .attrs
            .iter()
            .map(|(k, v)| format!("{}=\"{}\"", k, v))
            .collect();
        s.push('[');
        s.push_str(&attrs.join(","));
        s.push(']');
    }
    s.push(';');
    s
}

fn render_endpoint(ep: &EndPoint) -> String {
    match &ep.port {
        Some(p) => format!("{}:{}", ep.node, p),
        None => ep.node.clone(),
    }
}

fn render_cluster(c: &Cluster) -> String {
    let mut lines = vec![
        "nodesep=\"0.6\";".to_string(),
        "ranksep=\"0.6\";".to_string(),
        format!("label=\"{}\";", c.label),
        "style=\"filled\";".to_string(),
        format!("color=\"{}\";", c.color),
        "penwidth=\"2\";".to_string(),
        format!("fillcolor=\"{}\";", c.color),
        "overlap=\"false\";".to_string(),
        "sep=\"4\";".to_string(),
    ];
    for s in &c.body {
        lines.push(render_stmt(s));
    }
    let open = format!("subgraph \"cluster_{}\" {{", c.label);
    render_block(&open, &lines)
}

fn render_rankblock(b: &RankBlock) -> String {
    let mut lines = vec![format!("rank=\"{}\";", b.rank)];
    for s in &b.body {
        lines.push(render_stmt(s));
    }
    render_block("{", &lines)
}

//! Node abbreviation (BEHAVIOR.md §5): assigning short NAMES to complex terms
//! and rendering the legend table.
//!
//! Three things here are fully determined by observation and byte-tested:
//!   * [`prefix_for_symbol`] — the `PREFIX` derivation,
//!   * [`Abbreviator`] — per-prefix sequential numbering + nesting substitution,
//!   * [`legend_html`] — the exact `<TABLE …>` bytes incl. the 65-space hang indent.
//!
//! The *selection* of which sub-terms to abbreviate (§5c) and the canonical
//! numbering tie-break (§5b) are not fully determinable black-box; [`select`]
//! provides a documented heuristic and the caller controls numbering order.

use std::collections::HashMap;

use crate::term::Term;

/// The opening tag of every legend table. Its byte length is the hang-indent
/// applied to continuation `<TR>` rows.
pub const TABLE_OPEN: &str =
    "<TABLE BORDER=\"1\" CELLBORDER=\"0\" CELLSPACING=\"3\" CELLPADDING=\"1\">";

/// `PREFIX` for an abbreviation name: the first two *alphabetic* characters of
/// `name`, uppercased (one char if only one letter exists). Non-letters (digits,
/// `_`, `.`) are skipped. This is applied to the root symbol's *name* — for a
/// function `f(..)` that is `f`; for a constant `'c'` it is `c`; for a variable
/// `~v`/`$v`/`v` it is `v`; for an infix operator it is the operator's function
/// name (see [`Term::root_symbol_name`], which maps `^`→`exp`, `*`→`mult`,
/// `++`→`union`, `⊕`→`xor`).
///
/// Examples (all observed): `sign`→`SI`, `senc`→`SE`, `hash`→`HA`, `h2`→`H`,
/// `KDF`→`KD`, `pk`→`PK`, `aenc`→`AE`, `exp`→`EX`, `mult`→`MU`, `union`→`UN`,
/// `xor`→`XO`, `uninitialized`→`UN`, `F_status`→`FS`, `AMF_UE_NGAP_ID`→`AM`.
pub fn prefix_for_symbol(name: &str) -> String {
    name.chars()
        .filter(|c| c.is_ascii_alphabetic())
        .take(2)
        .flat_map(|c| c.to_uppercase())
        .collect()
}

/// Assigns and remembers abbreviation names, de-duplicating identical terms and
/// numbering `1,2,3,…` per prefix in the order terms are [`Abbreviator::add`]ed.
///
/// Numbering order matches tamarin only where the canonical order is
/// unambiguous (see BEHAVIOR.md §5b); the caller decides insertion order.
#[derive(Default)]
pub struct Abbreviator {
    /// name -> the term it stands for, in insertion order.
    entries: Vec<(String, Term)>,
    /// canonical fully-expanded key -> assigned name (dedup).
    by_key: HashMap<String, String>,
    /// prefix -> next counter value.
    counters: HashMap<String, u32>,
}

impl Abbreviator {
    pub fn new() -> Self {
        Self::default()
    }

    /// Register `term` for abbreviation, returning its name. Terms that render
    /// identically (fully expanded) share one name.
    pub fn add(&mut self, term: Term) -> String {
        let key = term.render_full();
        if let Some(existing) = self.by_key.get(&key) {
            return existing.clone();
        }
        let prefix = prefix_for_symbol(&term.root_symbol_name());
        let n = self.counters.entry(prefix.clone()).or_insert(0);
        *n += 1;
        let name = format!("{}{}", prefix, n);
        self.by_key.insert(key, name.clone());
        self.entries.push((name.clone(), term));
        name
    }

    /// The name for an already-registered term, if any (by full rendering).
    pub fn name_of(&self, term: &Term) -> Option<&str> {
        self.by_key.get(&term.render_full()).map(String::as_str)
    }

    /// Legend rows `(name, expansion)` in insertion order. Each expansion renders
    /// the term one level with any registered *sub*-term replaced by its name
    /// (nesting, §5b: `EX1 = 'g'^MU1`). The expansion string is NOT yet
    /// HTML-escaped; [`legend_html`] escapes it.
    pub fn rows(&self) -> Vec<(String, String)> {
        self.entries
            .iter()
            .map(|(name, term)| (name.clone(), term.render_abbrev(&self.by_key, Some(name))))
            .collect()
    }

    /// Render the legend as the exact inner HTML of the `plain` node's label
    /// (the bytes between `label=<` and `>`). Empty if no entries.
    pub fn legend_html(&self) -> String {
        legend_html(&self.rows())
    }

    pub fn is_empty(&self) -> bool {
        self.entries.is_empty()
    }
    pub fn len(&self) -> usize {
        self.entries.len()
    }
}

/// HTML-escape a legend expansion: `&`→`&amp;`, `<`→`&lt;`, `>`→`&gt;`. Single
/// quotes and `* ^ ~ $ ⊕ ++` are left literal (as observed).
pub fn escape_expansion(s: &str) -> String {
    let mut out = String::with_capacity(s.len());
    for c in s.chars() {
        match c {
            '&' => out.push_str("&amp;"),
            '<' => out.push_str("&lt;"),
            '>' => out.push_str("&gt;"),
            _ => out.push(c),
        }
    }
    out
}

/// Render one legend row's `<TR>…</TR>` (expansion is escaped here).
fn legend_row(name: &str, expansion: &str) -> String {
    format!(
        "<TR><TD ALIGN=\"LEFT\" VALIGN=\"TOP\"><FONT COLOR=\"#000000\">{}</FONT></TD> <TD ALIGN=\"LEFT\" VALIGN=\"TOP\">=</TD> <TD ALIGN=\"LEFT\" VALIGN=\"TOP\">{}</TD></TR>",
        name,
        escape_expansion(expansion),
    )
}

/// The exact inner HTML for the legend `plain` node (between `label=<` and `>`):
/// `<TABLE …><TR>row0</TR>\n<65sp><TR>row1</TR>\n…<65sp><TR>rowN</TR></TABLE>`.
/// The first row is inline after the table tag; every continuation row is on its
/// own line indented by `TABLE_OPEN.len()` (= 65) spaces.
pub fn legend_html(rows: &[(String, String)]) -> String {
    if rows.is_empty() {
        return String::new();
    }
    let indent = " ".repeat(TABLE_OPEN.len());
    let mut s = String::new();
    s.push_str(TABLE_OPEN);
    for (i, (name, exp)) in rows.iter().enumerate() {
        if i > 0 {
            s.push('\n');
            s.push_str(&indent);
        }
        s.push_str(&legend_row(name, exp));
    }
    s.push_str("</TABLE>");
    s
}

/// A documented, **best-effort** selection heuristic (see BEHAVIOR.md §5c —
/// byte-parity of the selection set is NOT claimed). Returns the sub-terms of
/// `roots` that this heuristic would abbreviate, bottom-up (inner before outer),
/// each non-atomic sub-term whose [`Term::size`] ≥ `min_size`, keeping only those
/// occurring at least `min_occ` times across `roots`.
pub fn select(roots: &[Term], min_size: usize, min_occ: usize) -> Vec<Term> {
    let mut counts: HashMap<String, (usize, Term)> = HashMap::new();
    for r in roots {
        r.for_each_subterm(&mut |t| {
            if !t.is_atomic() && t.size() >= min_size {
                let e = counts.entry(t.render_full()).or_insert((0, t.clone()));
                e.0 += 1;
            }
        });
    }
    let mut picked: Vec<Term> = counts
        .into_values()
        .filter(|(c, _)| *c >= min_occ)
        .map(|(_, t)| t)
        .collect();
    // bottom-up: smaller terms first so inner names are assigned before outer.
    picked.sort_by_key(|t| t.size());
    picked
}

//! A minimal term model, sufficient to drive abbreviation (naming + expansion
//! rendering). It is an independent design; it renders tamarin-like surface
//! syntax for the common term shapes observed in legend expansions
//! (variables, constants, pairs, `exp`/`mult`/`union`/`xor`, function apps).
//!
//! Faithful reproduction of the solver's full term pretty-printer (all operators,
//! precedence, line wrapping) is out of scope — see BEHAVIOR.md §3a/§5. The
//! covered shapes are byte-tested against captured legend rows.

use std::collections::HashMap;

/// A term. Variable kinds mirror tamarin's surface decorations.
#[derive(Clone, Debug, PartialEq, Eq)]
pub enum Term {
    /// Fresh variable, rendered `~name`.
    Fresh(String),
    /// Public variable, rendered `$name`.
    Pub(String),
    /// Bare message/temporal variable, rendered `name`.
    Msg(String),
    /// Public constant, rendered `'name'`.
    Const(String),
    /// Right-nested pair; rendered flattened as `<a, b, c>`.
    Pair(Box<Term>, Box<Term>),
    /// `exp(base, e)`, rendered `base^e` (the exponent carries its own parens
    /// when it is a product/sum).
    Exp(Box<Term>, Box<Term>),
    /// An associative-commutative operator rendered infix inside parentheses:
    /// `mult`→`*`, `union`→`++`, `xor`→`⊕`. `func` is the logical name used for
    /// the abbreviation prefix.
    Ac { func: String, op: String, args: Vec<Term> },
    /// Ordinary prefix application `func(a, b, …)`.
    App { func: String, args: Vec<Term> },
}

impl Term {
    // ---- convenience constructors --------------------------------------

    pub fn fresh(n: &str) -> Term {
        Term::Fresh(n.to_string())
    }
    pub fn pubv(n: &str) -> Term {
        Term::Pub(n.to_string())
    }
    pub fn msg(n: &str) -> Term {
        Term::Msg(n.to_string())
    }
    pub fn cst(n: &str) -> Term {
        Term::Const(n.to_string())
    }
    pub fn app(func: &str, args: Vec<Term>) -> Term {
        Term::App { func: func.to_string(), args }
    }
    pub fn exp(base: Term, e: Term) -> Term {
        Term::Exp(Box::new(base), Box::new(e))
    }
    pub fn mult(args: Vec<Term>) -> Term {
        Term::Ac { func: "mult".into(), op: "*".into(), args }
    }
    pub fn union(args: Vec<Term>) -> Term {
        Term::Ac { func: "union".into(), op: "++".into(), args }
    }
    pub fn xor(args: Vec<Term>) -> Term {
        Term::Ac { func: "xor".into(), op: "\u{2295}".into(), args }
    }
    /// Build a flattened tuple `<a, b, c>` from ≥1 elements (right-nested pairs).
    pub fn tuple(mut elems: Vec<Term>) -> Term {
        let last = elems.pop().expect("tuple needs ≥1 element");
        elems.into_iter().rev().fold(last, |acc, e| Term::Pair(Box::new(e), Box::new(acc)))
    }

    // ---- naming --------------------------------------------------------

    /// The root symbol's *name*, whose first two letters give the abbreviation
    /// prefix (see [`crate::abbrev::prefix_for_symbol`]).
    pub fn root_symbol_name(&self) -> String {
        match self {
            Term::Fresh(n) | Term::Pub(n) | Term::Msg(n) | Term::Const(n) => n.clone(),
            Term::Pair(..) => "pair".to_string(),
            Term::Exp(..) => "exp".to_string(),
            Term::Ac { func, .. } => func.clone(),
            Term::App { func, .. } => func.clone(),
        }
    }

    /// Leaf terms (variables/constants) are atomic; everything else is not.
    pub fn is_atomic(&self) -> bool {
        matches!(self, Term::Fresh(_) | Term::Pub(_) | Term::Msg(_) | Term::Const(_))
    }

    /// Number of term nodes (atoms + operators) — a simple complexity measure.
    pub fn size(&self) -> usize {
        match self {
            _ if self.is_atomic() => 1,
            Term::Pair(a, b) => 1 + a.size() + b.size(),
            Term::Exp(a, b) => 1 + a.size() + b.size(),
            Term::Ac { args, .. } | Term::App { args, .. } => {
                1 + args.iter().map(Term::size).sum::<usize>()
            }
        }
    }

    /// Visit this term and every sub-term (pre-order).
    pub fn for_each_subterm(&self, f: &mut dyn FnMut(&Term)) {
        f(self);
        match self {
            Term::Pair(a, b) | Term::Exp(a, b) => {
                a.for_each_subterm(f);
                b.for_each_subterm(f);
            }
            Term::Ac { args, .. } | Term::App { args, .. } => {
                for a in args {
                    a.for_each_subterm(f);
                }
            }
            _ => {}
        }
    }

    // ---- rendering -----------------------------------------------------

    /// Fully-expanded surface rendering (no abbreviations). Used as the dedup key.
    pub fn render_full(&self) -> String {
        self.render_with(&|t| t.render_full())
    }

    /// Render this term's expansion, replacing any *registered* sub-term (present
    /// in `table`, keyed by its full rendering) with its abbreviation name. The
    /// top-level term itself is always rendered structurally.
    pub fn render_abbrev(&self, table: &HashMap<String, String>) -> String {
        self.render_with(&|t| t.substitute(table))
    }

    /// Rendering used for children during abbreviation: a registered term yields
    /// its name, otherwise it renders structurally (recursing on its children).
    fn substitute(&self, table: &HashMap<String, String>) -> String {
        if let Some(name) = table.get(&self.render_full()) {
            return name.clone();
        }
        self.render_with(&|t| t.substitute(table))
    }

    /// Structural rendering; `child` renders each immediate sub-term.
    fn render_with(&self, child: &dyn Fn(&Term) -> String) -> String {
        match self {
            Term::Fresh(n) => format!("~{}", n),
            Term::Pub(n) => format!("${}", n),
            Term::Msg(n) => n.clone(),
            Term::Const(n) => format!("'{}'", n),
            Term::Pair(..) => {
                let elems = self.pair_spine();
                let parts: Vec<String> = elems.iter().map(|t| child(t)).collect();
                format!("<{}>", parts.join(", "))
            }
            Term::Exp(base, e) => format!("{}^{}", child(base), child(e)),
            Term::Ac { op, args, .. } => {
                let parts: Vec<String> = args.iter().map(|t| child(t)).collect();
                format!("({})", parts.join(op))
            }
            Term::App { func, args } => {
                let parts: Vec<String> = args.iter().map(|t| child(t)).collect();
                format!("{}({})", func, parts.join(", "))
            }
        }
    }

    /// Flatten a right-nested pair into its element spine.
    fn pair_spine(&self) -> Vec<&Term> {
        let mut out = Vec::new();
        let mut cur = self;
        while let Term::Pair(a, b) = cur {
            out.push(a.as_ref());
            cur = b.as_ref();
        }
        out.push(cur);
        out
    }
}

//! # graph-clean
//!
//! A clean-room reimplementation of the tamarin-prover web-UI constraint-system
//! graph payload — the graphviz DOT text served at
//! `/thy/trace/N/interactive-graph-def/proof/…`.
//!
//! Everything here was derived from BLACK-BOX observation of captured payloads
//! and live probing of the compiled server; see `workspace/BEHAVIOR.md` for the
//! observed spec and `workspace/QUERIES.log` for the oracle interactions. No
//! tamarin-prover source was consulted.
//!
//! ## What it does
//! * [`model`] — an independent graph data model (nodes, edges, clusters, legend).
//! * [`dot::to_dot`] — a **byte-exact** DOT serializer for that model.
//! * [`term`] — a small term model backing abbreviation expansions.
//! * [`abbrev`] — node abbreviation: prefix derivation, per-prefix numbering,
//!   and byte-exact legend-table HTML.
//!
//! ## Clustering / simplification trigger
//! The compact (clustered) header is used exactly when a graph carries a node
//! with a role other than `Undefined`; [`model::Graph::infer_header`] applies
//! this observed rule.
//!
//! ```
//! use graph_clean::model::*;
//! let mut g = Graph::new(Header::Simple);
//! g.push(Stmt::Node(Node::ellipse("n7", Ellipse::new("#vf : isend"))));
//! let dot = graph_clean::dot::to_dot(&g);
//! assert!(dot.starts_with("digraph \"G\" {\nnodesep=\"0.3\";"));
//! assert!(dot.ends_with("\n\n}\n"));
//! ```

pub mod abbrev;
pub mod dot;
pub mod model;
pub mod term;

pub use dot::to_dot;
pub use model::{Graph, Header};
pub use term::Term;

