//! Byte-parity round-trip tests against captured DOT payloads.
//!
//! A minimal parser for the exact DOT dialect the tamarin web UI emits reads
//! each captured fixture into the crate's own [`Graph`] model; re-serializing
//! with [`graph_clean::dot::to_dot`] must reproduce the original bytes exactly.
//! This validates the payload-format spec (BEHAVIOR.md §2, §3) end to end.

use graph_clean::dot::to_dot;
use graph_clean::model::*;

// ----------------------------------------------------------------------------
// Parser for the captured DOT dialect (test-only ingest).
// ----------------------------------------------------------------------------

/// Merge a plain-node legend that spans several physical lines into one logical
/// line, so every statement is a single element.
fn logical_lines(dot: &str) -> Vec<String> {
    let raw: Vec<&str> = dot.split('\n').collect();
    let mut out: Vec<String> = Vec::new();
    let mut i = 0;
    while i < raw.len() {
        let line = raw[i];
        if line.contains("shape=\"plain\"") && !line.trim_end().ends_with("];") {
            let mut buf = String::from(line);
            i += 1;
            loop {
                buf.push('\n');
                buf.push_str(raw[i]);
                if raw[i].trim_end().ends_with("];") {
                    break;
                }
                i += 1;
            }
            out.push(buf);
            i += 1;
        } else {
            out.push(line.to_string());
            i += 1;
        }
    }
    out
}

fn parse(dot: &str) -> Graph {
    let lines = logical_lines(dot);
    let header = if lines.iter().any(|l| l == "packmode=\"cluster\";") {
        Header::Compact
    } else {
        Header::Simple
    };
    // Body is everything strictly inside the outermost `digraph "G" {` … `}`.
    let mut idx = lines.iter().position(|l| l == "digraph \"G\" {").unwrap() + 1;
    let mut g = Graph::new(header);
    g.body = parse_block(&lines, &mut idx);
    g
}

/// Parse statements until the matching `}` (which it consumes). `idx` points at
/// the first inner line.
fn parse_block(lines: &[String], idx: &mut usize) -> Vec<Stmt> {
    let mut out = Vec::new();
    while *idx < lines.len() {
        let line = lines[*idx].clone();
        let trimmed = line.trim_end();
        if trimmed == "}" {
            *idx += 1;
            return out;
        }
        if trimmed.is_empty() || is_block_attr(trimmed) {
            *idx += 1;
            continue;
        }
        if trimmed.starts_with("subgraph \"cluster_") {
            let label = trimmed
                .trim_start_matches("subgraph \"cluster_")
                .trim_end_matches("\" {")
                .to_string();
            *idx += 1;
            // capture color, then inner nodes
            let color = capture_attr(lines, *idx, "color").unwrap();
            let body = parse_block(lines, idx);
            out.push(Stmt::Cluster(Cluster { label, color, body }));
            continue;
        }
        if trimmed == "{" {
            *idx += 1;
            let rank = capture_attr(lines, *idx, "rank").unwrap();
            let body = parse_block(lines, idx);
            out.push(Stmt::RankBlock(RankBlock { rank, body }));
            continue;
        }
        // node or edge statement (single logical line)
        if line.contains(" -> ") {
            out.push(Stmt::Edge(parse_edge(&line)));
        } else {
            out.push(Stmt::Node(parse_node(&line)));
        }
        *idx += 1;
    }
    out
}

/// True for lines that are block attributes (regenerated by the serializer, so
/// dropped on ingest).
fn is_block_attr(l: &str) -> bool {
    if l.starts_with("node[") || l.starts_with("edge[") {
        return true;
    }
    // key="..."; where key is lowercase — but NOT a node/edge stmt (those have '[').
    if l.contains('[') {
        return false;
    }
    if let Some(eq) = l.find('=') {
        let key = &l[..eq];
        return key.chars().all(|c| c.is_ascii_lowercase() || c.is_ascii_digit())
            && l.ends_with(';');
    }
    false
}

fn capture_attr(lines: &[String], from: usize, key: &str) -> Option<String> {
    let needle = format!("{}=\"", key);
    for l in &lines[from..] {
        let t = l.trim();
        if t.starts_with(&needle) {
            let rest = &t[needle.len()..];
            return Some(rest.trim_end_matches("\";").trim_end_matches('"').to_string());
        }
        if t == "}" {
            break;
        }
    }
    None
}

fn parse_node(line: &str) -> Node {
    let l = line.trim_end();
    let br = l.find('[').unwrap();
    let id = l[..br].to_string();
    let attrs = &l[br + 1..l.rfind("];").unwrap()];
    if attrs.starts_with("shape=\"record\"") {
        // shape="record",label="…",fillcolor="…",style="filled",fontcolor="…",role="…"
        let label_start = l.find(",label=\"").unwrap() + ",label=\"".len();
        let label_end = l.find("\",fillcolor=\"").unwrap();
        let label = &l[label_start..label_end];
        let fillcolor = extract(l, "fillcolor=\"");
        let fontcolor = extract(l, "fontcolor=\"");
        let role = extract(l, "role=\"");
        Node::record(
            id,
            Record {
                columns: parse_record_label(label),
                fillcolor,
                fontcolor,
                role: Role(role),
            },
        )
    } else if attrs.starts_with("shape=\"plain\"") {
        let start = l.find("label=<").unwrap() + "label=<".len();
        let end = l.rfind(">];").unwrap();
        Node::plain(id, &l[start..end])
    } else {
        // ellipse: label="…",shape="ellipse"[,color="…"]
        let label_start = l.find("label=\"").unwrap() + "label=\"".len();
        let label_end = l.find("\",shape=\"ellipse\"").unwrap();
        let label = l[label_start..label_end].to_string();
        let color = if l.contains(",color=\"") {
            Some(extract(l, ",color=\""))
        } else {
            None
        };
        Node::ellipse(id, Ellipse { label, color })
    }
}

fn extract(l: &str, key: &str) -> String {
    let s = l.find(key).unwrap() + key.len();
    let rest = &l[s..];
    let e = rest.find('"').unwrap();
    rest[..e].to_string()
}

/// `{{<p> t|<p> t}|{<p> t}|…}` → columns of ported cells.
fn parse_record_label(s: &str) -> Vec<Vec<Cell>> {
    let inner = &s[1..s.len() - 1]; // strip outer { }
    split_top(inner, '|')
        .into_iter()
        .map(|group| {
            let g = &group[1..group.len() - 1]; // strip group { }
            split_top(g, '|')
                .into_iter()
                .map(|cell| parse_cell(&cell))
                .collect()
        })
        .collect()
}

fn parse_cell(cell: &str) -> Cell {
    // `<port> text`
    let gt = find_unescaped(cell, '>').unwrap();
    let port = cell[1..gt].to_string();
    let text = cell[gt + 2..].to_string(); // skip "> "
    Cell { port, text }
}

/// Split on `sep` at brace-depth 0, honoring backslash escapes.
fn split_top(s: &str, sep: char) -> Vec<String> {
    let mut parts = Vec::new();
    let mut depth = 0i32;
    let mut cur = String::new();
    let mut esc = false;
    for c in s.chars() {
        if esc {
            cur.push(c);
            esc = false;
            continue;
        }
        match c {
            '\\' => {
                cur.push(c);
                esc = true;
            }
            '{' => {
                depth += 1;
                cur.push(c);
            }
            '}' => {
                depth -= 1;
                cur.push(c);
            }
            _ if c == sep && depth == 0 => {
                parts.push(std::mem::take(&mut cur));
            }
            _ => cur.push(c),
        }
    }
    parts.push(cur);
    parts
}

fn find_unescaped(s: &str, target: char) -> Option<usize> {
    let mut esc = false;
    for (i, c) in s.char_indices() {
        if esc {
            esc = false;
            continue;
        }
        if c == '\\' {
            esc = true;
        } else if c == target {
            return Some(i);
        }
    }
    None
}

fn parse_edge(line: &str) -> Edge {
    let l = line.trim_end().trim_end_matches(';');
    let arrow = l.find(" -> ").unwrap();
    let src = parse_endpoint(&l[..arrow]);
    let rest = &l[arrow + 4..];
    let (dst_str, attrs) = match rest.find('[') {
        Some(b) => (&rest[..b], parse_attrs(&rest[b + 1..rest.rfind(']').unwrap()])),
        None => (rest, Vec::new()),
    };
    Edge {
        src,
        dst: parse_endpoint(dst_str),
        attrs,
    }
}

fn parse_endpoint(s: &str) -> EndPoint {
    match s.find(':') {
        Some(c) => EndPoint::port(s[..c].to_string(), s[c + 1..].to_string()),
        None => EndPoint::node(s.to_string()),
    }
}

fn parse_attrs(s: &str) -> Vec<(String, String)> {
    // k="v",k="v",…
    let mut out = Vec::new();
    for part in s.split("\",") {
        let part = part.trim_end_matches('"');
        if let Some(eq) = part.find("=\"") {
            out.push((part[..eq].to_string(), part[eq + 2..].to_string()));
        }
    }
    out
}

// ----------------------------------------------------------------------------
// Tests
// ----------------------------------------------------------------------------

fn check(name: &str, dot: &str) {
    let g = parse(dot);
    let out = to_dot(&g);
    assert_eq!(out, dot, "byte round-trip mismatch for fixture {name}");
    // The inferred header must match what the fixture actually uses.
    assert_eq!(g.infer_header(), g.header, "header trigger mismatch for {name}");
}

#[test]
fn roundtrip_empty() {
    check("empty", include_str!("fixtures/empty.dot"));
}

#[test]
fn roundtrip_simple_ports() {
    check("simple_ports", include_str!("fixtures/simple_ports.dot"));
}

#[test]
fn roundtrip_simple_abbrev() {
    check("simple_abbrev", include_str!("fixtures/simple_abbrev.dot"));
}

#[test]
fn roundtrip_compact_clusters() {
    check("compact_clusters", include_str!("fixtures/compact_clusters.dot"));
}

#[test]
fn roundtrip_compact_abbrev() {
    check("compact_abbrev", include_str!("fixtures/compact_abbrev.dot"));
}

#[test]
fn roundtrip_multi_abbrev() {
    check("multi_abbrev", include_str!("fixtures/multi_abbrev.dot"));
}

//! Abbreviation + clustering tests, grounded in observed payloads
//! (BEHAVIOR.md §4, §5).

use graph_clean::abbrev::{legend_html, prefix_for_symbol, Abbreviator, TABLE_OPEN};
use graph_clean::model::*;
use graph_clean::term::Term;

/// Extract the inner HTML of the first `plain` legend node (bytes between
/// `label=<` and `>];`).
fn legend_inner(dot: &str) -> String {
    let anchor = dot.find("shape=\"plain\",label=<").unwrap();
    let start = anchor + dot[anchor..].find("label=<").unwrap() + "label=<".len();
    let end = start + dot[start..].find(">];").unwrap();
    dot[start..end].to_string()
}

#[test]
fn table_open_tag_is_65_bytes() {
    // The legend hang-indent equals this tag's byte length (BEHAVIOR.md §5a).
    assert_eq!(TABLE_OPEN.len(), 65);
}

#[test]
fn prefix_rule_matches_observed_names() {
    // (root symbol name, observed prefix) pairs taken from the corpus legend.
    let cases = [
        ("sign", "SI"),
        ("senc", "SE"),
        ("second", "SE"),
        ("hash", "HA"),
        ("h", "H"),
        ("h2", "H"),
        ("KDF", "KD"),
        ("kdf1", "KD"),
        ("pk", "PK"),
        ("aenc", "AE"),
        ("aead", "AE"),
        ("adec", "AD"),
        ("pmult", "PM"),
        ("plus", "PL"),
        ("pdec", "PD"),
        ("inv", "IN"),
        ("mac", "MA"),
        ("blind", "BL"),
        ("idsign", "ID"),
        // operator function names
        ("exp", "EX"),
        ("mult", "MU"),
        ("union", "UN"),
        ("xor", "XO"),
        // constants (unquoted names), non-letters skipped
        ("uninitialized", "UN"),
        ("F_status", "FS"),
        ("ho_req_ack", "HO"),
        ("no_message_state", "NO"),
        ("K_gNB_star", "KG"),
        // variables (undecorated names)
        ("AMF_UE_NGAP_ID", "AM"),
        ("cid_N26", "CI"),
        ("gNB_UE_ID", "GN"),
        ("commitmsg", "CO"),
        ("StateChannel", "ST"),
    ];
    for (name, expect) in cases {
        assert_eq!(prefix_for_symbol(name), expect, "prefix for {name:?}");
    }
}

#[test]
fn operator_terms_report_function_name_for_prefix() {
    assert_eq!(Term::mult(vec![Term::msg("a")]).root_symbol_name(), "mult");
    assert_eq!(Term::union(vec![Term::msg("a")]).root_symbol_name(), "union");
    assert_eq!(Term::xor(vec![Term::msg("a")]).root_symbol_name(), "xor");
    assert_eq!(Term::exp(Term::cst("g"), Term::msg("a")).root_symbol_name(), "exp");
    assert_eq!(prefix_for_symbol(&Term::mult(vec![]).root_symbol_name()), "MU");
}

#[test]
fn term_renders_observed_surface_syntax() {
    // H2 = h(<$I.1, $R.1, X, 'g'^~ekR, z, 'g'^(~lkR.1*~x.2)>)   (from multi_abbrev)
    let h2 = Term::app(
        "h",
        vec![Term::tuple(vec![
            Term::pubv("I.1"),
            Term::pubv("R.1"),
            Term::msg("X"),
            Term::exp(Term::cst("g"), Term::fresh("ekR")),
            Term::msg("z"),
            Term::exp(Term::cst("g"), Term::mult(vec![Term::fresh("lkR.1"), Term::fresh("x.2")])),
        ])],
    );
    assert_eq!(
        h2.render_full(),
        "h(<$I.1, $R.1, X, 'g'^~ekR, z, 'g'^(~lkR.1*~x.2)>)"
    );
    // (~ekR*x*~ekR.1)
    assert_eq!(
        Term::mult(vec![Term::fresh("ekR"), Term::msg("x"), Term::fresh("ekR.1")]).render_full(),
        "(~ekR*x*~ekR.1)"
    );
    // ('1'++'1'++z)
    assert_eq!(
        Term::union(vec![Term::cst("1"), Term::cst("1"), Term::msg("z")]).render_full(),
        "('1'++'1'++z)"
    );
}

#[test]
fn abbreviator_numbers_and_nests() {
    // Register MU1 first, then EX1 = 'g'^MU1 must reference it (nesting, §5b).
    let mut ab = Abbreviator::new();
    let mu = Term::mult(vec![Term::fresh("ekR"), Term::msg("x"), Term::fresh("ekR.1")]);
    let ex = Term::exp(Term::cst("g"), mu.clone());
    assert_eq!(ab.add(mu), "MU1");
    assert_eq!(ab.add(ex), "EX1");
    // second, structurally-identical mult dedups to MU1 (no MU2).
    let mu2 = Term::mult(vec![Term::fresh("ekR"), Term::msg("x"), Term::fresh("ekR.1")]);
    assert_eq!(ab.add(mu2), "MU1");
    let rows = ab.rows();
    assert_eq!(rows, vec![
        ("MU1".to_string(), "(~ekR*x*~ekR.1)".to_string()),
        ("EX1".to_string(), "'g'^MU1".to_string()),
    ]);
}

#[test]
fn per_prefix_counter_increments() {
    let mut ab = Abbreviator::new();
    assert_eq!(ab.add(Term::app("sign", vec![Term::fresh("a")])), "SI1");
    assert_eq!(ab.add(Term::app("sign", vec![Term::fresh("b")])), "SI2");
    assert_eq!(ab.add(Term::app("senc", vec![Term::fresh("c")])), "SE1");
    assert_eq!(ab.add(Term::app("sign", vec![Term::fresh("d")])), "SI3");
}

#[test]
fn legend_html_single_row_matches_fixture() {
    let dot = include_str!("fixtures/simple_abbrev.dot");
    let expected = legend_inner(dot);
    // SI1 = sign(<'2', $I, $R, hki, 'g'^~ekR>, ~ltkI)   (raw; legend escapes < >)
    let rows = vec![(
        "SI1".to_string(),
        "sign(<'2', $I, $R, hki, 'g'^~ekR>, ~ltkI)".to_string(),
    )];
    assert_eq!(legend_html(&rows), expected);
}

#[test]
fn legend_html_multi_row_matches_fixture() {
    let dot = include_str!("fixtures/multi_abbrev.dot");
    let expected = legend_inner(dot);
    // Rows in the fixture's order (order itself is a documented gap, §5b);
    // this asserts the RENDERING is byte-exact: escaping + 65-space hang indent.
    let rows: Vec<(String, String)> = [
        ("EX2", "'g'^(~ekR*x)"),
        ("EX3", "'g'^~ekR.1"),
        ("EX4", "'g'^~lkR.1"),
        ("H2", "h(<$I.1, $R.1, X, 'g'^~ekR, z, 'g'^(~lkR.1*~x.2)>)"),
        ("MU1", "(~ekR*x*~ekR.1)"),
        ("EX1", "'g'^MU1"),
        ("H1", "h(<$I, $R, EX2, EX3, EX1, 'g'^(~lkR*~x.1)>)"),
        ("MU2", "(x*~ekR.1)"),
    ]
    .iter()
    .map(|(a, b)| (a.to_string(), b.to_string()))
    .collect();
    assert_eq!(legend_html(&rows), expected);
}

#[test]
fn legend_via_terms_and_abbreviator_matches_fixture() {
    // Reproduce the simple_abbrev legend end-to-end from a Term model + the
    // Abbreviator (naming + rendering), not from a hand-written row list.
    let dot = include_str!("fixtures/simple_abbrev.dot");
    let expected = legend_inner(dot);
    let si = Term::app(
        "sign",
        vec![
            Term::tuple(vec![
                Term::cst("2"),
                Term::pubv("I"),
                Term::pubv("R"),
                Term::msg("hki"),
                Term::exp(Term::cst("g"), Term::fresh("ekR")),
            ]),
            Term::fresh("ltkI"),
        ],
    );
    let mut ab = Abbreviator::new();
    assert_eq!(ab.add(si), "SI1");
    assert_eq!(ab.legend_html(), expected);
